import { useNavigate } from 'react-router-dom';

function WelcomeScreen() {
  const navigate = useNavigate();

  const handleStart = () => {
    navigate('/second'); // Navigate to second screen
  };

  return (
    <div>
      <h1>Welcome!</h1>
      <button onClick={handleStart}>Start</button>
    </div>
  );
}

export default WelcomeScreen();
